starterCode.css:
body { font-family: system-ui, sans-serif; padding: 24px; color: #171a22; }
main { max-width: 760px; margin: auto; }
form { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 8px; margin-bottom: 16px; }
input, button { padding: 9px; }
table { width: 100%; border-collapse: collapse; }
th, td { border-bottom: 1px solid #d9dee8; padding: 10px; text-align: left; }
#media { font-weight: 700; }

